javascript:(function(){const e={};e.name=document.querySelector('h1')?.textContent.trim()||'',e.headline=document.querySelector('div.text-body-medium.break-words')?.textContent.trim()||'',e.about=document.querySelector('section.pv-profile-card')?.textContent.trim()||'';const t=document.querySelector('#experience')?.parentElement,n=t?t.querySelectorAll('ul li'):[];e.experience=Array.from(n).map(e=>{const t=e.querySelector('div.hoverable-link-text.t-bold span[aria-hidden="true"]')?.textContent.trim()||'',n=e.querySelector('span.t-14.t-normal')?.textContent.trim()||'',l=e.querySelector('span.t-14.t-normal.t-black--light')?.textContent.trim()||'';return{title:t,company:n,dates:l}}),e.posts=Array.from(document.querySelectorAll('.feed-shared-update-v2')).map(e=>{const t=e.querySelector('.update-components-text')?.innerText.trim()||'',n=e.querySelector('.update-components-actor__sub-description-link')?.textContent.trim()||'';return{text:t,date:n}}),e.education=[];const l=JSON.stringify(e,null,2),o=document.createElement('textarea');o.value=l,document.body.appendChild(o),o.select();try{document.execCommand('copy'),alert('Profile copied to clipboard!')}catch(e){console.error('Failed to copy: ',e),alert('Failed to copy profile. Check console for details.')}document.body.removeChild(o)})();